function GroupedTable() {
  const groups: Record<string, { name: string; amount: string }[]> = {
    'Q1 2025': [{ name: 'January', amount: '$12,400' }, { name: 'February', amount: '$14,200' }, { name: 'March', amount: '$11,800' }],
